INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0001-0000-0000-000000000000', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'text', '{"html":"<h3>Measurement Is the Heart of Surveying</h3><p>Surveying is, at bottom, the art and science of <strong>measurement</strong>: determining the relative positions of points on, above, or below the surface of the earth. Every plat, every boundary retracement, every construction stakeout, and every topographic map rests on a foundation of measured quantities. Before you can adjust a traverse, compute an area, or set a corner, you must understand what a measurement <em>is</em> and what it is <em>not</em>.</p><p>The single most important idea in this entire module is deceptively simple: <strong>no measurement is ever exact.</strong> A distance you tape as 250.00 ft is not <em>truly</em> 250.00 ft &mdash; it is your best estimate of a value you can never know with perfect certainty. The instant you accept this, you stop asking the naive question \"What is the right answer?\" and start asking the professional question \"How good is my answer, and how do I know?\" Error theory is the framework that lets you answer the second question rigorously.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0001-0000-0000-000000000001', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'text', '{"html":"<h3>Direct vs. Indirect Measurement</h3><p>Surveyors obtain quantities in two ways. A <strong>direct measurement</strong> compares the quantity against a standard unit applied directly to it: laying a steel tape end-to-end along a line, or reading a graduated circle to obtain an angle. An <strong>indirect measurement</strong> is computed from other measured values using a mathematical relationship. When you determine the length of a slope distance from a measured horizontal distance and a measured vertical angle, or compute the distance to an inaccessible point from a triangle, you are measuring <em>indirectly</em>.</p><p>This distinction matters because <strong>errors flow through computation</strong>. An indirect result is only as reliable as the directly measured quantities that feed it, combined according to the rules of error propagation (covered later in this module). A surveyor who understands which numbers were measured and which were computed knows where to look when a result is suspect.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0001-0000-0000-000000000002', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'text', '{"html":"<h3>What Surveyors Measure</h3><p>Despite the variety of modern instruments &mdash; total stations, GNSS receivers, digital levels, laser scanners &mdash; nearly everything a surveyor determines reduces to four fundamental measured quantities:</p><ul><li><strong>Horizontal distances</strong> &mdash; the projected length of a line on a horizontal plane.</li><li><strong>Vertical distances</strong> (differences in elevation) &mdash; the basis of leveling.</li><li><strong>Horizontal angles</strong> &mdash; measured in a horizontal plane between two directions.</li><li><strong>Vertical (or zenith) angles</strong> &mdash; measured in a vertical plane from horizontal or from the zenith.</li></ul><p>From these, every position, area, and volume is derived. Each quantity has standard units: distances in U.S. survey feet, international feet, or meters (and historically chains and Texas <strong>varas</strong>, where 1 vara = 33&frac13; in); angles in degrees-minutes-seconds (sexagesimal) or, less commonly in U.S. practice, grads/radians.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0001-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'callout', '{"type":"info","text":"Texas heritage unit: the vara (33 1/3 inches) appears throughout original GLO grant field notes. 36 varas = exactly 100 ft, and roughly 5,645.4 square varas equal one acre. You will convert vara distances when retracing Spanish, Mexican, and Republic-era surveys."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0001-0000-0000-000000000004', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'text', '{"html":"<h3>True Value, Error, and the Most Probable Value</h3><p>The <strong>true value</strong> of a quantity is its exact, theoretically correct magnitude. It exists, but it is <em>unknowable</em> &mdash; we can never measure anything perfectly. The <strong>error</strong> of any single observation is the difference between the observed value and the (unknown) true value. Because we cannot know the true value, we also cannot know the exact error of a measurement.</p><p>What we <em>can</em> do is make repeated, redundant observations and combine them to obtain a <strong>most probable value</strong> &mdash; the value statistics tells us is most likely to be closest to the truth. For a set of equally reliable direct measurements of one quantity, that most probable value is simply the <strong>arithmetic mean</strong>. The difference between each observation and the most probable value is called a <strong>residual</strong>, and residuals (which we <em>can</em> compute) are the practical stand-in for the errors we cannot. This chain of ideas &mdash; true value &rarr; error &rarr; most probable value &rarr; residual &rarr; precision estimate &mdash; is the spine of everything that follows.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0001-0000-0000-000000000005', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Repeated observations scatter around the (unknown) true value; the mean is the most probable value, and residuals measure spread from it."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0001-0000-0000-000000000006', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'key_takeaways', '{"title":"Key Takeaways","items":["Surveying is fundamentally measurement, and no measurement is ever exact.","Direct measurements are applied to the quantity itself; indirect measurements are computed from other measured values.","The four basic measured quantities are horizontal distance, vertical distance, horizontal angle, and vertical angle.","The true value is unknowable; the most probable value (the mean of equal observations) is our best estimate, and residuals stand in for unknown errors."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0002-0000-0000-000000000000', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'text', '{"html":"<h3>Three Kinds of Error</h3><p>Because no measurement is exact, every observation differs from the truth by some amount. Surveyors classify the sources of that difference into three categories with very different behaviors and very different cures: <strong>systematic errors</strong>, <strong>random errors</strong>, and <strong>blunders</strong> (also called mistakes or gross errors). Knowing which kind you are dealing with tells you whether to <em>correct</em> it, <em>adjust for</em> it, or <em>throw the observation out</em>.</p><p>A clean mental model: systematic errors are the <em>bias</em> in your work, random errors are the irreducible <em>scatter</em>, and blunders are <em>outright mistakes</em> that do not belong in the data set at all. A professional measurement program is designed to eliminate systematic error, minimize random error, and expose blunders through redundancy.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0002-0000-0000-000000000001', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'text', '{"html":"<h3>Systematic Errors</h3><p>A <strong>systematic error</strong> follows a physical law and therefore behaves in a consistent, predictable way: under the same conditions it has the same sign and magnitude. Classic examples in distance measurement include a steel tape that is too long or too short relative to its nominal length, thermal expansion or contraction of the tape, sag, incorrect tension, and the reduction of slope distance to horizontal. Each can be quantified with a formula or a calibration constant and <strong>removed</strong>.</p><p>Because systematic errors accumulate in the same direction, they are dangerous: taping a 1,000-ft line in fifty 20-ft increments with a tape 0.01 ft too short produces a 0.50 ft error that never averages out. Repeating the measurement does not help &mdash; you simply repeat the bias. The remedy is to <strong>calibrate equipment, apply corrections, and design procedures</strong> that cancel the systematic effect (for example, balanced backsight/foresight distances in leveling to cancel collimation and curvature)."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0002-0000-0000-000000000002', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'text', '{"html":"<h3>Random Errors</h3><p><strong>Random (accidental) errors</strong> are the small residual variations that remain after all blunders are removed and all systematic effects are corrected. They arise from limitations in the observer, the instrument, and the environment &mdash; the last digit you estimate on a scale, slight pointing imperfections, momentary atmospheric shimmer. Random errors have three defining statistical properties:</p><ul><li>Small errors occur more frequently than large ones.</li><li>Positive and negative errors of the same size are equally likely.</li><li>Very large random errors are essentially impossible (they would be blunders).</li></ul><p>Collectively they follow the <strong>normal, or Gaussian, distribution</strong> &mdash; the familiar bell curve. Because plus and minus errors are equally likely, random errors <em>tend to cancel</em> when observations are averaged, which is precisely why repeating a measurement and taking the mean improves the result. Random error is unavoidable; it can be minimized and characterized statistically, but never eliminated.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0002-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'callout', '{"type":"warning","text":"Do not confuse a blunder with a random error. A blunder (transposing 152 as 125, reading the wrong tape graduation, miscounting tape lengths) is a mistake, not a statistical error. Blunders must be DETECTED and REMOVED. Including a blunder in a mean or least-squares adjustment corrupts the entire result."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0002-0000-0000-000000000004', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'text', '{"html":"<h3>Blunders (Mistakes)</h3><p>A <strong>blunder</strong> is a gross human error: misreading an instrument, recording a digit wrong, sighting the wrong target, dropping or adding a full tape length, or transposing numbers in the field book. Blunders are typically large, do not follow the normal distribution, and have no place in the data. They cannot be \"adjusted\" &mdash; they must be <strong>found and eliminated</strong> before any statistical treatment.</p><p>The chief defense against blunders is <strong>redundancy</strong>: measure angles by repetition, close traverses and level loops back on known points, double-measure distances, and apply independent geometric checks (the angles of a closed polygon must sum to a known value; the misclosure of a level loop must be near zero). When a check fails by a large amount, a blunder is almost certainly present. Good field procedure &mdash; consistent routines, immediate checking, and never relying on a single unverified observation &mdash; keeps blunders out of the record.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0002-0000-0000-000000000005', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'table', '{"headers":["Property","Systematic error","Random error","Blunder"],"rows":[["Source","Physical law / equipment","Observer + instrument + environment limits","Human mistake"],["Sign","Consistent (predictable)","Plus or minus equally likely","Either; usually large"],["Behavior on repetition","Accumulates (does not cancel)","Tends to cancel (averages out)","Erratic / unique"],["Remedy","Calibrate & apply correction","Take redundant observations, average","Detect and discard"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0002-0000-0000-000000000006', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'key_takeaways', '{"title":"Key Takeaways","items":["Systematic errors are predictable and one-directional; they accumulate and must be removed by calibration or correction formulas.","Random errors are small, sign-balanced, unavoidable, and follow the normal distribution; they tend to cancel when averaged.","Blunders are mistakes, not statistical errors; they must be detected and discarded, never adjusted.","Redundant observations and geometric checks are the surveyor''s main tool for catching blunders."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0003-0000-0000-000000000000', 'b1466895-7138-43f6-8f99-8565d7b42962', 'text', '{"html":"<h3>Two Words That Are Not Synonyms</h3><p>In everyday speech \"precise\" and \"accurate\" are used interchangeably; in surveying they mean two distinctly different things, and confusing them leads to bad decisions. <strong>Precision</strong> describes how closely repeated measurements of the same quantity agree <em>with one another</em> &mdash; the tightness of the cluster, governed by <strong>random error</strong>. <strong>Accuracy</strong> describes how close a measurement (or its mean) is to the <em>true value</em> &mdash; governed by the absence of <strong>systematic error and blunders</strong>.</p><p>Crucially, the two are <strong>independent</strong>. You can be precise without being accurate, and a single careful measurement can be accurate without your having any evidence of precision. The most insidious case in practice is high precision masking poor accuracy: a tightly repeatable set of distances taped with a tape 0.02 ft too short will agree beautifully with each other and all be wrong by the same amount.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0003-0000-0000-000000000001', 'b1466895-7138-43f6-8f99-8565d7b42962', 'text', '{"html":"<h3>The Dartboard Analogy</h3><p>The classic way to picture the difference is a target. Imagine four shooters each firing several shots:</p><ul><li><strong>Accurate and precise</strong> &mdash; tight cluster centered on the bull''s-eye. This is the goal: small random error and no bias.</li><li><strong>Precise but not accurate</strong> &mdash; a tight cluster, but off to one side. Small random error, but a <em>systematic</em> shift (a constant bias or an uncorrected error).</li><li><strong>Accurate but not precise</strong> &mdash; shots scattered widely but centered on the bull''s-eye on average. Large random error, but no net bias; the mean is good even though individual shots are not.</li><li><strong>Neither</strong> &mdash; widely scattered and off-center. Large random error <em>and</em> bias.</li></ul><p>The lesson: tight grouping (precision) tells you nothing by itself about whether you are hitting the truth (accuracy). You need an independent check &mdash; a known distance, a closed loop, a redundant geometry &mdash; to confirm accuracy.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0003-0000-0000-000000000002', 'b1466895-7138-43f6-8f99-8565d7b42962', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: The classic four-target illustration of precision (scatter) versus accuracy (bias)."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0003-0000-0000-000000000003', 'b1466895-7138-43f6-8f99-8565d7b42962', 'text', '{"html":"<h3>Expressing Precision as a Ratio</h3><p>In linear surveying, precision is frequently reported as a <strong>relative precision</strong> &mdash; a dimensionless ratio comparing the size of the error (or misclosure) to the total distance measured. A traverse with a perimeter of 4,000.00 ft that closes with a linear misclosure of 0.40 ft has a relative precision of 0.40 / 4,000 = 1/10,000, written <strong>1:10,000</strong>. The larger the second number, the better the work: 1:20,000 is twice as precise as 1:10,000.</p><p>Relative precision is powerful because it lets you compare jobs of different size and set minimum standards by survey type. Rural boundary traverses might require 1:5,000 to 1:10,000; urban and high-value work commonly demands 1:10,000 or better. Note that relative precision is a measure of <em>internal consistency</em> (precision/closure), not a guarantee of accuracy &mdash; a traverse can close beautifully and still be tied to the wrong control.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0003-0000-0000-000000000004', 'b1466895-7138-43f6-8f99-8565d7b42962', 'equation', '{"latex":"\\text{Relative precision} = \\frac{\\text{misclosure}}{\\text{perimeter}} = 1 : \\frac{\\text{perimeter}}{\\text{misclosure}}","label":"Relative precision as a ratio","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0003-0000-0000-000000000005', 'b1466895-7138-43f6-8f99-8565d7b42962', 'callout', '{"type":"warning","text":"A low (good) misclosure ratio proves precision, not accuracy. A traverse that closes at 1:50,000 but was started from a mis-recorded control coordinate is precisely placed in the wrong location. Always verify accuracy with an independent tie to reliable control."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0003-0000-0000-000000000006', 'b1466895-7138-43f6-8f99-8565d7b42962', 'key_takeaways', '{"title":"Key Takeaways","items":["Precision = agreement of repeated measurements (random error); accuracy = closeness to truth (freedom from bias).","Precision and accuracy are independent: you can be precise yet inaccurate.","The dartboard analogy: tight cluster = precise; centered on the bull = accurate.","Relative precision (e.g., 1:10,000) compares misclosure to total distance and measures internal consistency, not accuracy."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0004-0000-0000-000000000000', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'text', '{"html":"<h3>Why Digits Carry Meaning</h3><p><strong>Significant figures</strong> are the digits in a measured value that are known reliably plus one final digit that is estimated. They are not a cosmetic convention &mdash; they are a statement about <strong>precision</strong>. Writing a taped distance as 250.0 ft claims you know the value to the nearest tenth; writing 250.000 ft claims knowledge to the nearest thousandth. If your tape and method support only tenths, the extra zeros are a <em>false claim</em> of precision that misleads anyone who relies on the number.</p><p>The guiding principle: the rightmost significant digit is the <strong>first uncertain digit</strong>. A reading of 12.47 ft says \"I am confident in 12.4 and I estimate the 7.\" Recording, computing, and reporting at the correct number of significant figures keeps a survey honest about how good its numbers really are.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0004-0000-0000-000000000001', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'text', '{"html":"<h3>Counting Significant Figures</h3><p>The rules for counting significant figures:</p><ul><li><strong>All nonzero digits are significant.</strong> 345.6 has four.</li><li><strong>Zeros between nonzero digits are significant.</strong> 4007 has four; 30.05 has four.</li><li><strong>Leading zeros are never significant</strong> &mdash; they only locate the decimal. 0.0042 has two.</li><li><strong>Trailing zeros after a decimal point are significant.</strong> 12.300 has five; that is the whole point of writing them.</li><li><strong>Trailing zeros in a whole number are ambiguous.</strong> 1200 could be two, three, or four; resolve it with scientific notation (1.20 &times; 10<sup>3</sup> = three) or a written tolerance.</li></ul><p>In surveying, the field-book convention is to record exactly the digits the instrument and method justify &mdash; for example, a total station distance to 0.01 ft and an angle to the nearest second &mdash; so the recorded value itself communicates the precision.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0004-0000-0000-000000000002', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'text', '{"html":"<h3>Significant Figures in Computation</h3><p>Two different rules govern how significant figures carry through arithmetic:</p><ul><li><strong>Addition and subtraction</strong> &mdash; the result is rounded to the <em>least number of decimal places</em> among the inputs. 125.30 + 4.7 + 0.085 = 130.085, reported as <strong>130.1</strong> (limited by 4.7, which has one decimal place).</li><li><strong>Multiplication and division</strong> &mdash; the result keeps the <em>least number of significant figures</em> among the inputs. 250.0 (4 s.f.) &times; 3.14159 (6 s.f.) = 785.3975, reported as <strong>785.4</strong> (4 s.f.).</li></ul><p>A practical workflow: <strong>carry one or two guard digits through intermediate steps and round only the final answer.</strong> Rounding at every step introduces accumulated rounding error that can swamp the precision you were trying to preserve. Exact constants (like the 43,560 sq ft in an acre, or an integer count of tape lengths) have unlimited significant figures and never limit the result.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0004-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'table', '{"headers":["Value","Significant figures","Why"],"rows":[["345.6","4","All nonzero digits count."],["0.0042","2","Leading zeros are not significant."],["4007","4","Embedded zeros are significant."],["12.300","5","Trailing zeros after the decimal are significant."],["1200","ambiguous (2-4)","Use scientific notation to resolve."]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0004-0000-0000-000000000004', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'text', '{"html":"<h3>Rounding Without Introducing Bias</h3><p>The familiar \"round half up\" rule (0.5 always rounds up) introduces a small <strong>systematic bias</strong>, because the boundary case always pushes in the same direction. Over thousands of computations that bias accumulates. Surveyors and metrologists therefore prefer <strong>round-half-to-even</strong> (the \"banker''s rounding\" rule): when the digit to be dropped is exactly 5 with nothing significant after it, round to the nearest <em>even</em> digit. Thus 2.45 &rarr; 2.4, while 2.55 &rarr; 2.6. Half the time you round up and half the time down, so the rounding errors cancel rather than accumulate.</p><p>Whatever convention you adopt, two habits protect your work: <strong>round only once, at the end</strong>, and <strong>report a result no more precisely than its least-precise input.</strong> A computed area cannot be more precise than the distances that produced it, no matter how many digits your calculator displays.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0004-0000-0000-000000000005', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'key_takeaways', '{"title":"Key Takeaways","items":["Significant figures express precision; the last significant digit is the estimated, uncertain one.","Leading zeros never count; embedded zeros and trailing zeros after a decimal always count; trailing zeros in whole numbers are ambiguous.","Add/subtract: limit by decimal places. Multiply/divide: limit by count of significant figures.","Carry guard digits and round only the final answer; round-half-to-even avoids systematic rounding bias."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000000', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'text', '{"html":"<h3>Errors Combine in Quadrature</h3><p>Real survey results are almost always <strong>computed</strong> from several measured quantities &mdash; a perimeter from many taped segments, a coordinate from a distance and a bearing, an area from two sides. Each input carries random error, so the question is: how do those input errors combine into the error of the result? The answer, for independent random errors, is the <strong>law of propagation of random errors</strong>: they combine by <strong>root-sum-square</strong> (in quadrature), not by simple addition.</p><p>The reason is statistical. Because random errors are equally likely to be positive or negative, they partially cancel when summed. Arithmetic addition (assuming every error has the same sign and conspires against you) overstates the realistic combined error; quadrature gives the <em>most probable</em> combined error. This single idea &mdash; squares add &mdash; underlies every propagation formula below.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000001', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'equation', '{"latex":"E_{\\text{sum}} = \\sqrt{e_1^{2} + e_2^{2} + \\cdots + e_n^{2}}","label":"Error of a sum (independent random errors)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000002', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'text', '{"html":"<h3>Error of a Sum and a Series</h3><p>When a total is the sum of several independently measured parts, the error of the sum is the root-sum-square of the individual errors. A common special case is a line measured in <strong>n equal segments</strong>, each with the same expected random error <em>e</em> (for example, taping a long line in repeated 100-ft pulls, each pull with error e). Then:</p><ul><li>The error of the total is <strong>E = e&middot;&radic;n</strong> &mdash; the <em>error of a series</em>.</li></ul><p>This result is profound and slightly counterintuitive: the total error grows only as the <strong>square root</strong> of the number of segments, not in proportion to it. Doubling the number of equal legs does <em>not</em> double the random error of the line &mdash; it increases it by only &radic;2 &asymp; 1.41. (Note that this concerns <em>random</em> error only; a systematic per-leg error <em>does</em> add directly and grows in proportion to n &mdash; another reason to separate the two error types.)</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'equation', '{"latex":"E_{\\text{series}} = e\\sqrt{n}","label":"Error of a series of n equal measurements","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000004', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'text', '{"html":"<h3>Standard Error of the Mean</h3><p>The flip side of the series rule explains <em>why we average</em>. If you observe a single quantity n times, each observation having standard deviation &sigma; (the spread of a single measurement), the most probable value is the mean, and the precision of that mean &mdash; the <strong>standard error of the mean</strong> &mdash; is:</p><ul><li><strong>&sigma;<sub>mean</sub> = &sigma; / &radic;n</strong></li></ul><p>Averaging n observations therefore improves precision by the factor &radic;n. Four observations halve the standard error; nine observations cut it to one-third. The diminishing return is important to recognize: going from 1 to 4 observations buys a 2&times; improvement, but going from 4 to 16 only buys another 2&times;. This is why surveyors take a sensible number of repetitions &mdash; enough to drive random error below the tolerance, but not so many that the labor outweighs the benefit.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000005', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'equation', '{"latex":"\\sigma_{\\bar{x}} = \\frac{\\sigma}{\\sqrt{n}}","label":"Standard error of the mean","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000006', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'text', '{"html":"<h3>Error in a Product (Areas)</h3><p>When a result is a <strong>product</strong> of measured quantities &mdash; classically a rectangular area A = L &times; W &mdash; it is the <em>relative</em> errors that combine in quadrature. If side L has standard error &sigma;<sub>L</sub> and side W has &sigma;<sub>W</sub>, then the relative error of the area is the root-sum-square of the relative errors of the sides:</p><ul><li>(&sigma;<sub>A</sub>/A)<sup>2</sup> = (&sigma;<sub>L</sub>/L)<sup>2</sup> + (&sigma;<sub>W</sub>/W)<sup>2</sup></li></ul><p>From which the absolute error in the area is &sigma;<sub>A</sub> = A &middot; &radic;[(&sigma;<sub>L</sub>/L)<sup>2</sup> + (&sigma;<sub>W</sub>/W)<sup>2</sup>]. The practical takeaway: in a product, the factor with the <em>largest relative error dominates</em> the result, so effort spent tightening the weakest measurement pays off most. This is the same root-sum-square logic as the sum rule, applied to fractional rather than absolute errors.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000007', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'equation', '{"latex":"\\sigma_{A} = A\\sqrt{\\left(\\frac{\\sigma_L}{L}\\right)^{2} + \\left(\\frac{\\sigma_W}{W}\\right)^{2}}","label":"Error of a product (area A = L x W)","display":"block"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000008', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'callout', '{"type":"info","text":"Quadrature rule of thumb: when one input error is much larger than the others, it dominates the combined error almost completely, because sqrt(3^2 + 1^2) = 3.16 is barely more than 3. Spend your precision budget on the weakest link."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0005-0000-0000-000000000009', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'key_takeaways', '{"title":"Key Takeaways","items":["Independent random errors propagate in quadrature (root-sum-square), not by simple addition.","Error of a sum: E = sqrt(e1^2 + ... + en^2); for n equal legs, E = e*sqrt(n).","Standard error of the mean = sigma/sqrt(n); averaging n observations improves precision by sqrt(n).","In a product such as an area, relative errors combine in quadrature and the largest relative error dominates."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000000', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'text', '{"html":"<h3>From Averaging to Adjustment</h3><p>When you measure one quantity several times and take the mean, you are already doing a tiny least-squares adjustment without knowing it. <strong>Least squares</strong> generalizes that idea to whole networks &mdash; traverses, level loops, GNSS vectors &mdash; where many observations of <em>different</em> quantities must all be reconciled into one consistent set of coordinates. It is the rigorous, statistically defensible method that has replaced ad hoc rules (compass rule, transit rule) for high-quality work, and it is built into every modern survey-network adjustment package.</p><p>The motivating problem is <strong>redundancy</strong>. If you measure exactly enough to determine the unknowns, there is one answer and no check. If you measure <em>more</em> than necessary &mdash; which good practice demands &mdash; the surplus observations will not perfectly agree, and you need a principled way to find the single \"best\" set of values. Least squares provides that principle.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000001', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'text', '{"html":"<h3>The Principle of Least Squares</h3><p>The principle states: <strong>the most probable values of the unknowns are those that make the sum of the squares of the (weighted) residuals a minimum.</strong> A residual is the difference between an observation and the adjusted value the solution assigns to it. Squaring the residuals does two things: it makes all terms positive (so plus and minus residuals cannot cancel and hide a poor fit), and it penalizes large residuals disproportionately, which matches the behavior of the normal distribution that random errors follow.</p><p>For the simplest case &mdash; n equally reliable observations of a single quantity &mdash; the value that minimizes &Sigma;v<sup>2</sup> is exactly the <strong>arithmetic mean</strong>. That is the mathematical justification for averaging: the mean is not merely convenient, it is the least-squares (most probable) estimator. For larger problems the same minimization is solved with matrix algebra, but the underlying principle never changes.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000002', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'equation', '{"latex":"\\text{minimize} \\quad \\sum_{i=1}^{n} w_i v_i^{2} \\qquad v_i = x_i - \\bar{x}","label":"Principle of least squares (weighted residuals)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'text', '{"html":"<h3>Most Probable Value, Residuals, and Standard Deviation</h3><p>Given n equally weighted observations x<sub>i</sub> of one quantity, the workflow is:</p><ul><li><strong>Most probable value (mean):</strong> x&#772; = (&Sigma;x<sub>i</sub>) / n.</li><li><strong>Residuals:</strong> v<sub>i</sub> = x<sub>i</sub> &minus; x&#772; (they always sum to zero, which is a useful check).</li><li><strong>Standard deviation of a single observation:</strong> &sigma; = &radic;[ &Sigma;v<sub>i</sub><sup>2</sup> / (n &minus; 1) ].</li><li><strong>Standard error of the mean:</strong> &sigma;<sub>mean</sub> = &sigma; / &radic;n.</li></ul><p>The standard deviation is the fundamental measure of <strong>precision</strong> (spread) of the observations. The standard error of the mean tells you how well the <em>average</em> is determined. Both quantities are essential to reporting a result honestly: a measured length is properly stated not as a bare number but as a value <em>plus or minus</em> its standard error.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000004', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'equation', '{"latex":"\\sigma = \\sqrt{\\frac{\\sum_{i=1}^{n} v_i^{2}}{n-1}}","label":"Sample standard deviation of a single observation","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000005', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'text', '{"html":"<h3>Degrees of Freedom: Why n - 1?</h3><p>You may wonder why the standard deviation divides by <strong>n &minus; 1</strong> rather than n. The answer is <strong>degrees of freedom</strong> (the redundancy). To compute the residuals you first had to compute the mean <em>from the same data</em>; that consumes one degree of freedom, because once n &minus; 1 of the residuals are known the last one is fixed (the residuals must sum to zero). Dividing by n &minus; 1 corrects for this and gives an <strong>unbiased</strong> estimate of the true standard deviation. With only a single observation (n = 1) there is no redundancy, n &minus; 1 = 0, and no estimate of precision is possible &mdash; which is exactly why a single unchecked measurement tells you nothing about its own quality.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000006', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'text', '{"html":"<h3>Weighted Observations</h3><p>So far we assumed every observation was equally reliable. In real networks they are not: a distance measured with a calibrated EDM deserves more influence than one paced off; an angle turned six times is better than one turned once. <strong>Weighted least squares</strong> handles this by assigning each observation a <strong>weight</strong> proportional to the inverse of its variance: w<sub>i</sub> = 1/&sigma;<sub>i</sub><sup>2</sup>. More reliable (smaller-variance) observations get larger weights and pull the solution toward themselves more strongly.</p><p>With weights, the most probable value of a single quantity becomes the <strong>weighted mean</strong>, x&#772; = (&Sigma;w<sub>i</sub>x<sub>i</sub>) / (&Sigma;w<sub>i</sub>), and the principle minimizes the <em>weighted</em> sum of squared residuals &Sigma;w<sub>i</sub>v<sub>i</sub><sup>2</sup>. Weighting is what lets a single rigorous adjustment combine GNSS vectors, total-station distances, and leveled heights &mdash; observations of wildly different precision &mdash; into one statistically optimal result.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000007', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'equation', '{"latex":"\\bar{x}_w = \\frac{\\sum w_i x_i}{\\sum w_i}, \\qquad w_i = \\frac{1}{\\sigma_i^{2}}","label":"Weighted mean and weight definition","display":"block"}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000008', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'callout', '{"type":"info","text":"Least squares is the modern standard for adjusting boundary and control surveys. Unlike the compass and transit rules (covered in the traverse module), it adjusts all observations simultaneously, respects their relative reliability through weights, and yields error estimates (standard deviations) for every adjusted coordinate."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0006-0000-0000-000000000009', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'key_takeaways', '{"title":"Key Takeaways","items":["The principle of least squares: the best values minimize the (weighted) sum of squared residuals; for one quantity this is the mean.","Standard deviation sigma = sqrt(sum v^2 / (n-1)); the n-1 reflects degrees of freedom and keeps the estimate unbiased.","Redundant observations are what make adjustment and a precision estimate possible.","Weighted least squares uses weights w = 1/sigma^2, so more reliable observations influence the solution more."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0007-0000-0000-000000000000', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'text', '{"html":"<h3>From Theory to the Field</h3><p>Everything in this module &mdash; error types, precision, propagation, least squares &mdash; converges on a single practical question: <strong>how do you actually take measurements that are good enough?</strong> The answer is a disciplined set of field procedures, each one targeted at a specific category of error. Systematic errors you <em>eliminate at the source</em>; random errors you <em>average down</em>; blunders you <em>expose with redundancy</em>. A surveyor who internalizes this three-part strategy produces data that adjust cleanly and stand up in court.</p><p>Good procedure is not optional polish. Because systematic errors accumulate and blunders can be catastrophic, the cost of a bad routine is paid not in the field but later &mdash; in a traverse that will not close, a boundary set in the wrong place, or a stakeout that has to be redone. The cheapest error to fix is the one you prevent.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0007-0000-0000-000000000001', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'text', '{"html":"<h3>Eliminating Systematic Error</h3><p>Because systematic errors have a known sign and magnitude, they can be removed by <strong>calibration, correction, and procedure</strong>:</p><ul><li><strong>Standardize and calibrate</strong> tapes, EDM/total stations, and levels against known baselines; apply the determined corrections.</li><li><strong>Apply correction formulas</strong> for temperature, tension, sag, and slope-to-horizontal reduction when taping.</li><li><strong>Balance backsight and foresight distances</strong> in differential leveling so collimation error, earth curvature, and refraction cancel between setups.</li><li><strong>Double-center / observe both faces</strong> (direct and reverse, face left and face right) when turning angles, so instrument errors of the line of sight and horizontal axis cancel in the mean.</li></ul><p>Each of these directly attacks a known physical bias. The hallmark of a systematic-error remedy is that it works by <em>design</em>, not by repetition &mdash; you cannot average away a one-directional error, you must cancel or correct it.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0007-0000-0000-000000000002', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'text', '{"html":"<h3>Reducing Random Error</h3><p>Random error cannot be eliminated, only minimized and characterized. The principal tools follow directly from the propagation rules:</p><ul><li><strong>Repeat and average.</strong> Turning an angle by repetition or observing a distance several times and meaning the results reduces the random error of the mean by &radic;n (the standard-error-of-the-mean rule).</li><li><strong>Use appropriate, well-maintained instruments.</strong> A one-second total station has smaller per-observation random error than a one-minute instrument; sharp optics and stable tribrachs reduce pointing scatter.</li><li><strong>Control the environment and procedure.</strong> Steady the rod, shade the instrument from differential heating, avoid sighting through heat shimmer, and keep sight lengths reasonable.</li></ul><p>The diminishing-returns principle from the propagation lesson applies here: take enough repetitions to push random error comfortably below the project tolerance, but recognize that beyond a point additional observations buy little precision for a lot of labor.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0007-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'text', '{"html":"<h3>Catching Blunders with Redundancy</h3><p>Blunders are large and unpredictable, so the only reliable defense is to build in <strong>independent checks</strong> that a blunder will violate conspicuously:</p><ul><li><strong>Close the figure.</strong> A loop traverse must return to its start; the angles of a closed polygon must sum to (n &minus; 2) &times; 180&deg;. A large angular misclosure flags a blunder.</li><li><strong>Close level loops</strong> back onto a known benchmark; a misclosure far beyond the expected random spread means a mistake, not noise.</li><li><strong>Double-measure</strong> critical distances and re-read critical angles; agreement is a check, disagreement a warning.</li><li><strong>Verify in real time.</strong> Reduce and check field data before leaving the site, while it is still cheap to re-observe.</li></ul><p>The unifying idea is that <strong>a measurement you cannot check, you cannot trust.</strong> Redundancy is not wasted effort &mdash; it is the mechanism that converts a pile of observations into a defensible result, and it is also the very redundancy that makes least-squares adjustment and precision estimation possible.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0007-0000-0000-000000000004', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'callout', '{"type":"warning","text":"A single unchecked observation has no measure of its own quality and no defense against a blunder. Always build redundancy into the survey: close loops, turn angles multiple times, and tie to at least two independent control points."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0007-0000-0000-000000000005', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'table', '{"headers":["Error type","Field strategy","Example procedure"],"rows":[["Systematic","Eliminate at source","Calibrate tape/EDM; balance BS/FS; temperature & sag corrections"],["Random","Minimize and average","Repeat angles/distances; better instrument; control environment"],["Blunder","Detect and discard","Close loops; angle-sum check; double measurements; field reduction"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0310-0007-0000-0000-000000000006', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'key_takeaways', '{"title":"Key Takeaways","items":["Match the remedy to the error: calibrate/correct systematic error, average down random error, expose blunders with checks.","Balanced backsight/foresight distances and observing both instrument faces cancel important systematic instrument errors.","Repeating and averaging observations reduces random error by sqrt(n).","Redundancy and independent geometric checks (closures, angle sums, double measurements) are the defense against blunders."]}'::jsonb, 6);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000001', 'True value', 'The theoretically exact, correct magnitude of a measured quantity. It exists but can never be determined exactly by measurement.', 'We aim for it but never reach it.', 'c1000003-0000-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000002', 'Most probable value', 'The value, derived from redundant observations, that is statistically most likely to be closest to the true value. For equally weighted observations of a single quantity it is the arithmetic mean.', NULL, 'c1000003-0000-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000003', 'Direct vs. indirect measurement', 'A direct measurement applies a standard unit to the quantity itself (taping a distance). An indirect measurement is computed from other measured quantities (a distance found from an angle and a baseline).', NULL, 'c1000003-0000-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000004', 'Residual', 'The difference between an individual observation and the most probable value (v = x - mean). Residuals are computable and serve as the practical substitute for unknown true errors.', NULL, 'c1000003-0000-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000005', 'Systematic error', 'An error that follows a physical law and has a consistent sign and magnitude under like conditions, so it accumulates and can be modeled, calibrated out, or removed by a correction formula.', 'Same direction every time; does not average out.', 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000006', 'Random (accidental) error', 'Small, unavoidable variation remaining after blunders and systematic errors are removed; equally likely to be plus or minus and following the normal distribution, so it tends to cancel on averaging.', NULL, 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000007', 'Blunder (mistake)', 'A gross human error such as a misreading, a transposition, or a dropped tape length. It is not a statistical error and must be detected and removed from the data, never adjusted.', NULL, 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000008', 'Normal (Gaussian) distribution', 'The bell-shaped probability curve that random errors follow: small errors are common, large errors rare, and positive and negative errors of equal size are equally likely.', NULL, 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000009', 'Precision', 'The degree of agreement among repeated measurements of the same quantity; controlled by random error (scatter). High precision means a tight cluster, regardless of correctness.', 'Repeatability.', 'c1000003-0000-0000-0000-000000000003', 'b1466895-7138-43f6-8f99-8565d7b42962', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000010', 'Accuracy', 'The closeness of a measurement, or its mean, to the true value; controlled by the absence of systematic error and blunders (bias).', NULL, 'c1000003-0000-0000-0000-000000000003', 'b1466895-7138-43f6-8f99-8565d7b42962', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000011', 'Relative precision', 'A dimensionless ratio of error (or misclosure) to total distance, such as 1:10,000. It expresses internal consistency and is used to set survey accuracy standards.', NULL, 'c1000003-0000-0000-0000-000000000003', 'b1466895-7138-43f6-8f99-8565d7b42962', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000012', 'Significant figures', 'The digits in a measured value that are reliably known plus one estimated final digit. They communicate the precision of the measurement and must not be overstated.', NULL, 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000013', 'Sig-fig rule (add/subtract)', 'When adding or subtracting, round the result to the least number of decimal places present in any input value.', 'Decimal places, not digit count.', 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000014', 'Sig-fig rule (multiply/divide)', 'When multiplying or dividing, the result retains the least number of significant figures present in any input value.', NULL, 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000015', 'Round-half-to-even (banker''s rounding)', 'A rounding convention in which an exact half rounds to the nearest even digit (2.45 to 2.4, 2.55 to 2.6), so rounding errors cancel instead of accumulating into a systematic bias.', NULL, 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000016', 'Error of a sum', 'For independent random errors, the error of a sum of measured parts is the root-sum-square of the individual errors: E = sqrt(e1^2 + e2^2 + ... + en^2).', 'Squares add.', 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000017', 'Error of a series', 'For a quantity formed by n equal measurements each with random error e, the total random error is E = e*sqrt(n). It grows only as the square root of the number of legs.', NULL, 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000018', 'Standard error of the mean', 'The precision of an averaged value: sigma_mean = sigma / sqrt(n). Averaging n equally weighted observations reduces the random error by the factor sqrt(n).', NULL, 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000019', 'Propagation in a product', 'For a product such as area = L x W, the relative errors combine in quadrature: (sigmaA/A)^2 = (sigmaL/L)^2 + (sigmaW/W)^2.', NULL, 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000020', 'Principle of least squares', 'The rule that the most probable values of the unknowns are those minimizing the sum of the squares of the (weighted) residuals. For repeated observations of one quantity, the solution is the arithmetic mean.', 'Minimize the sum of squared residuals.', 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000021', 'Standard deviation (sample)', 'A measure of the spread (precision) of observations: sigma = sqrt(sum of squared residuals / (n-1)). The n-1 denominator gives an unbiased estimate.', NULL, 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000022', 'Degrees of freedom', 'The number of redundant observations, equal to (observations - unknowns). Computing the mean from the data consumes one, which is why a single-quantity standard deviation divides by n-1.', NULL, 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000023', 'Weight (of an observation)', 'A number proportional to the inverse of an observation''s variance, w = 1/sigma^2, used in weighted least squares so that more reliable observations influence the adjusted result more.', NULL, 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000024', 'Balancing backsight and foresight', 'Keeping backsight and foresight sight distances equal in differential leveling so that collimation error, earth curvature, and refraction cancel between setups.', 'Equal sight lengths in leveling.', 'c1000003-0000-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000025', 'Double-centering (two faces)', 'Observing an angle in both the direct and reversed positions (face left and face right) and meaning the results, which cancels instrument errors in the line of sight and horizontal axis.', NULL, 'c1000003-0000-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000026', 'Redundancy', 'Taking more observations than the minimum needed, providing independent checks that expose blunders and supply the degrees of freedom required for adjustment and precision estimates.', NULL, 'c1000003-0000-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0340-0000-0000-0000-000000000027', 'Loop closure check', 'Returning a traverse or level run to a known starting point so that the misclosure can be evaluated. A large misclosure indicates a blunder or excessive error.', NULL, 'c1000003-0000-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', 'surveying', ARRAY['buildout','module-3']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000001', 'Which statement about measurement in surveying is correct?', 'multiple_choice', '["A carefully made measurement can be exactly equal to the true value.","Every measurement contains some error, and the true value can never be known exactly.","Indirect measurements are always more accurate than direct measurements.","The true value of a quantity equals the most probable value."]'::jsonb, 'Every measurement contains some error, and the true value can never be known exactly.', 'No measurement is ever exact; the true value is theoretical and unknowable. The most probable value (e.g., the mean) is our best estimate, not the true value, and indirect measurements are not inherently more accurate.', 'easy', 'c1000003-0000-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000002', 'Determining a distance to an inaccessible point by computing it from a measured baseline and measured angles is an example of:', 'multiple_choice', '["A direct measurement","An indirect measurement","A blunder","A systematic error"]'::jsonb, 'An indirect measurement', 'An indirect measurement is computed from other measured quantities using a mathematical relationship, rather than applying a unit directly to the quantity itself.', 'easy', 'c1000003-0000-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000003', 'The difference between an individual observation and the most probable value of a set is called the residual.', 'true_false', '["True","False"]'::jsonb, 'True', 'A residual is v = x - mean. Because the true value is unknown, residuals (which are computable) serve as the practical stand-in for the unknown true errors.', 'easy', 'c1000003-0000-0000-0000-000000000003', '5e9763a8-6772-4fcf-866f-5c61b1d525cf', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000004', 'A steel tape that is 0.01 ft shorter than its nominal length is used to measure a long line in many full tape lengths. The resulting error is best classified as:', 'multiple_choice', '["A random error that averages out with repetition","A systematic error that accumulates in one direction","A blunder that should be discarded","Negligible because tapes are always correct"]'::jsonb, 'A systematic error that accumulates in one direction', 'A tape of wrong length produces a consistent, one-directional error that accumulates with each tape length and does not cancel on repetition. It is corrected by calibration, not averaging.', 'medium', 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000005', 'Which of the following is NOT a property of random errors?', 'multiple_choice', '["Small errors occur more frequently than large ones.","Positive and negative errors of equal size are equally likely.","They follow the normal (Gaussian) distribution.","They accumulate in a consistent direction and never cancel."]'::jsonb, 'They accumulate in a consistent direction and never cancel.', 'Accumulating in a consistent direction describes systematic error. Random errors are sign-balanced, follow the normal distribution, and tend to cancel when averaged.', 'medium', 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000006', 'Transposing the field-book entry 152.46 as 125.46 is an example of a:', 'multiple_choice', '["Systematic error","Random error","Blunder (mistake)","Standard deviation"]'::jsonb, 'Blunder (mistake)', 'Transposing digits is a gross human mistake (blunder). Blunders do not follow the normal distribution and must be detected and removed, not adjusted.', 'easy', 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000007', 'A blunder can be safely left in the data because a least-squares adjustment will average it away.', 'true_false', '["True","False"]'::jsonb, 'False', 'Blunders are not statistical errors and corrupt any adjustment they enter. They must be detected and removed before the data are adjusted.', 'medium', 'c1000003-0000-0000-0000-000000000003', '9442daa4-8a0c-4b34-90f7-80304ebb0e20', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000008', 'A set of distances is taped repeatedly with a tape 0.02 ft too short. The measurements agree with each other to within 0.005 ft. This set is best described as:', 'multiple_choice', '["Accurate but not precise","Precise but not accurate","Both accurate and precise","Neither accurate nor precise"]'::jsonb, 'Precise but not accurate', 'Tight agreement (0.005 ft) means high precision, but the 0.02 ft systematic bias from the short tape makes every value wrong by the same amount, so accuracy is poor.', 'medium', 'c1000003-0000-0000-0000-000000000003', 'b1466895-7138-43f6-8f99-8565d7b42962', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000009', 'Precision is primarily a function of random error, while accuracy is primarily a function of systematic error (bias).', 'true_false', '["True","False"]'::jsonb, 'True', 'Random error (scatter) controls precision; systematic error and blunders (bias) control accuracy. The two are independent properties.', 'easy', 'c1000003-0000-0000-0000-000000000003', 'b1466895-7138-43f6-8f99-8565d7b42962', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000010', 'A closed traverse with a perimeter of 3,000 ft has a linear misclosure of 0.30 ft. What is its relative precision?', 'multiple_choice', '["1:1,000","1:3,000","1:10,000","1:30,000"]'::jsonb, '1:10,000', 'Relative precision = perimeter / misclosure = 3,000 / 0.30 = 10,000, written 1:10,000.', 'medium', 'c1000003-0000-0000-0000-000000000003', 'b1466895-7138-43f6-8f99-8565d7b42962', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000011', 'How many significant figures are in the value 0.04070?', 'multiple_choice', '["Two","Three","Four","Five"]'::jsonb, 'Four', 'Leading zeros (0.0...) are not significant. The 4, the embedded 0, the 7, and the trailing 0 after the decimal are all significant, giving four.', 'medium', 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000012', 'Compute 125.30 + 4.7 + 0.085 and report it to the correct number of significant figures (addition/subtraction rule).', 'multiple_choice', '["130.085","130.09","130.1","130"]'::jsonb, '130.1', 'The sum is 130.085, but the addition rule limits the result to the least number of decimal places among the inputs. 4.7 has one decimal place, so the answer is 130.1.', 'medium', 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000013', 'Using round-half-to-even (banker''s rounding), 2.45 rounds to 2.4 while 2.55 rounds to 2.6.', 'true_false', '["True","False"]'::jsonb, 'True', 'Round-half-to-even rounds an exact half to the nearest even digit: 2.45 -> 2.4 (4 is even) and 2.55 -> 2.6 (6 is even). This prevents the systematic bias of always rounding up.', 'medium', 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000014', 'When multiplying measured quantities, the product should be reported with:', 'multiple_choice', '["The most decimal places of any factor","The least number of significant figures of any factor","As many digits as the calculator displays","The least number of decimal places of any factor"]'::jsonb, 'The least number of significant figures of any factor', 'For multiplication and division, the result keeps the least number of significant figures among the inputs. (The decimal-place rule applies to addition and subtraction.)', 'easy', 'c1000003-0000-0000-0000-000000000003', 'eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000015', 'Two independent distances have random errors of 0.03 ft and 0.04 ft. What is the expected error in their sum?', 'multiple_choice', '["0.07 ft","0.05 ft","0.01 ft","0.035 ft"]'::jsonb, '0.05 ft', 'Independent random errors combine in quadrature: sqrt(0.03^2 + 0.04^2) = sqrt(0.0009 + 0.0016) = sqrt(0.0025) = 0.05 ft. Simple addition (0.07) overstates the realistic error.', 'medium', 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000016', 'A line is taped in 9 equal legs, each with a random error of 0.02 ft. What is the expected random error of the total line length?', 'multiple_choice', '["0.18 ft","0.06 ft","0.02 ft","0.0067 ft"]'::jsonb, '0.06 ft', 'Error of a series E = e*sqrt(n) = 0.02 * sqrt(9) = 0.02 * 3 = 0.06 ft. Note it grows only as sqrt(n), not as n (which would give 0.18 ft).', 'medium', 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000017', 'A single angle observation has a standard deviation of 6 seconds. If the angle is observed 4 times and averaged, the standard error of the mean is:', 'multiple_choice', '["6 seconds","3 seconds","1.5 seconds","24 seconds"]'::jsonb, '3 seconds', 'Standard error of the mean = sigma/sqrt(n) = 6/sqrt(4) = 6/2 = 3 seconds. Averaging 4 observations halves the random error.', 'medium', 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000018', 'In propagating error into a rectangular area A = L x W, the relative error of the area is found by adding the relative errors of L and W in quadrature.', 'true_false', '["True","False"]'::jsonb, 'True', 'For a product, relative errors combine in quadrature: (sigmaA/A)^2 = (sigmaL/L)^2 + (sigmaW/W)^2. The factor with the largest relative error dominates the result.', 'hard', 'c1000003-0000-0000-0000-000000000003', '190ebc35-c5e8-4479-8f39-77c6e490d034', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000019', 'The principle of least squares determines the most probable values by:', 'multiple_choice', '["Minimizing the sum of the residuals","Minimizing the sum of the squares of the (weighted) residuals","Maximizing the number of observations","Setting all residuals to zero"]'::jsonb, 'Minimizing the sum of the squares of the (weighted) residuals', 'Least squares minimizes the sum of squared (weighted) residuals. Squaring prevents plus/minus residuals from cancelling and penalizes large residuals, matching the normal distribution.', 'medium', 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000020', 'The sample standard deviation of a single observation divides the sum of squared residuals by (n - 1) rather than n because:', 'multiple_choice', '["It makes the number larger to be conservative","Computing the mean from the data consumes one degree of freedom, so n - 1 keeps the estimate unbiased","n - 1 is easier to compute","The residuals do not sum to zero"]'::jsonb, 'Computing the mean from the data consumes one degree of freedom, so n - 1 keeps the estimate unbiased', 'The residuals are taken about the mean computed from the same data, which uses one degree of freedom (residuals must sum to zero). Dividing by n - 1 corrects for this and gives an unbiased estimate.', 'hard', 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000021', 'In weighted least squares, the weight assigned to an observation is:', 'multiple_choice', '["Directly proportional to its variance","Inversely proportional to its variance (w = 1/sigma^2)","Equal for all observations","Proportional to the number of observations"]'::jsonb, 'Inversely proportional to its variance (w = 1/sigma^2)', 'A weight is the inverse of the observation''s variance, w = 1/sigma^2. More reliable (smaller-variance) observations receive larger weights and influence the solution more.', 'medium', 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000022', 'For four equally weighted observations of a single quantity, what is the most probable value, and what should you name the quantity v_i = x_i - (most probable value)?', 'short_answer', '[]'::jsonb, 'The most probable value is the arithmetic mean; v_i is the residual.', 'For equally weighted observations of one quantity, the least-squares (most probable) value is the arithmetic mean, and the difference between each observation and the mean is the residual.', 'easy', 'c1000003-0000-0000-0000-000000000003', '703631b0-5d21-4272-b25a-9577c8a3bc05', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000023', 'Keeping backsight and foresight distances equal in differential leveling primarily serves to:', 'multiple_choice', '["Reduce random pointing error","Cancel systematic collimation error, earth curvature, and refraction","Detect blunders in the field book","Increase the number of degrees of freedom"]'::jsonb, 'Cancel systematic collimation error, earth curvature, and refraction', 'Balanced sight distances make these systematic effects equal on backsight and foresight so they cancel in the elevation difference. It is a procedure that removes systematic error by design.', 'medium', 'c1000003-0000-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000024', 'Which field practice is the primary defense against blunders?', 'multiple_choice', '["Applying temperature corrections to taped distances","Building in redundancy and independent geometric checks (loop closures, angle sums)","Using a higher-precision instrument","Rounding final answers to fewer significant figures"]'::jsonb, 'Building in redundancy and independent geometric checks (loop closures, angle sums)', 'Blunders are large and erratic; redundancy and independent checks (a loop that must close, angles that must sum to a known value) expose them. Corrections and better instruments address systematic and random error, not blunders.', 'medium', 'c1000003-0000-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0330-0000-0000-0000-000000000025', 'Repeating an angle observation several times and averaging is an effective way to remove a systematic instrument error.', 'true_false', '["True","False"]'::jsonb, 'False', 'Averaging reduces random error (by sqrt(n)) but cannot remove a one-directional systematic error. Systematic instrument errors are cancelled by procedures such as observing both faces (double-centering) or by calibration.', 'medium', 'c1000003-0000-0000-0000-000000000003', '4ae68562-9fd5-4869-8dca-f3c50cc77f9d', ARRAY['buildout','module-3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0360-0000-0000-0000-000000000001', 'A single observation of an angle has a standard deviation of {{sigma:f1}} seconds. The angle is observed {{n}} times and the results are averaged. Compute the STANDARD ERROR OF THE MEAN, in seconds.', 'numeric_input', '[]'::jsonb, '0', 'The standard error of the mean is sigma/sqrt(n) = {{sigma:f1}} / sqrt({{n}}) = {{sigma:f1}} / {{rootn:f1}} = {{_answer}} seconds. Averaging {{n}} observations reduces the random error by the factor sqrt({{n}}).', 'easy', 'c1000003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-3','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0350-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0360-0000-0000-0000-000000000002', 'A line is measured in {{n}} equal tape lengths. Each tape length has an independent random error of {{e:f3}} ft. Compute the expected RANDOM ERROR of the total line length, in feet.', 'numeric_input', '[]'::jsonb, '0', 'For n equal legs each with random error e, the error of the series is E = e*sqrt(n) = {{e:f3}} x sqrt({{n}}) = {{e:f3}} x {{rootn:f1}} = {{_answer}} ft. The total error grows only as the square root of the number of legs.', 'medium', 'c1000003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-3','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0350-0000-0000-0000-000000000002', 0.002);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0360-0000-0000-0000-000000000003', 'A closed traverse has a perimeter of {{perim:f2}} ft and a linear misclosure of {{misc:f3}} ft. Express its relative precision as the denominator D in the ratio 1:D (i.e., compute perimeter / misclosure). Report D rounded to the nearest whole number.', 'numeric_input', '[]'::jsonb, '0', 'Relative precision = perimeter / misclosure = {{perim:f2}} / {{misc:f3}} = {{_answer}}, written 1:{{_answer}}. A larger D means a more precise (tighter-closing) traverse.', 'medium', 'c1000003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-3','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0350-0000-0000-0000-000000000003', 5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0360-0000-0000-0000-000000000004', 'A rectangular parcel is measured as {{L:f1}} ft by {{W:f1}} ft (each value given to one decimal place, i.e., 4 significant figures). Compute the area and round it to 4 significant figures. Report the area in square feet to the nearest 1 sq ft.', 'numeric_input', '[]'::jsonb, '0', 'Area = {{L:f1}} x {{W:f1}} = {{raw:f2}} sq ft. Both sides carry 4 significant figures, so the product is reported to 4 significant figures: {{_answer}} sq ft. Do not report more digits than the measurements support.', 'easy', 'c1000003-0000-0000-0000-000000000003', NULL, ARRAY['buildout','module-3','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0350-0000-0000-0000-000000000004', 1);
