UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['No measurement is ever exact; every observation carries some error, and the true value is never perfectly known.','Surveyors make direct measurements (taping a line) and indirect measurements (computing a distance from angles).','The four fundamental quantities are horizontal distance, vertical distance (elevation), horizontal angle, and vertical angle.','Because the true value is unknowable, surveyors work with a most probable value derived from repeated observations.']::text[], learning_objectives=ARRAY['Explain why every physical measurement is an estimate that contains some error and can never be exact.','Distinguish between direct and indirect measurements and give surveying examples of each.','Identify the four basic quantities a surveyor measures and the units used to express them.','Describe how a ''true value'' differs from a ''most probable value'' in practice.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='5e9763a8-6772-4fcf-866f-5c61b1d525cf';
DELETE FROM lesson_blocks WHERE lesson_id='5e9763a8-6772-4fcf-866f-5c61b1d525cf';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Systematic errors follow physical laws, have a consistent sign and magnitude under like conditions, and are correctable by calibration or formula.','Random errors are small, unavoidable, equally likely to be plus or minus, and follow the normal distribution.','Blunders (mistakes) are gross human errors that must be found and eliminated, never blended into an adjustment.','Redundant observations and good procedure are the primary defenses against blunders.']::text[], learning_objectives=ARRAY['Define and distinguish systematic errors, random errors, and blunders (mistakes).','Explain why systematic errors are predictable and can be modeled or eliminated, while random errors cannot.','Describe the statistical behavior of random errors and the normal (Gaussian) distribution.','Recognize that blunders are not errors in the statistical sense and must be detected and removed, not adjusted.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='9442daa4-8a0c-4b34-90f7-80304ebb0e20';
DELETE FROM lesson_blocks WHERE lesson_id='9442daa4-8a0c-4b34-90f7-80304ebb0e20';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=25, key_takeaways=ARRAY['Precision is the closeness of repeated measurements to one another; accuracy is closeness to the true value.','A set can be precise but inaccurate (tight grouping in the wrong place) when a systematic error or blunder is present.','Random error controls precision; systematic error (bias) controls accuracy.','Surveyors often express precision as a dimensionless ratio such as 1:10,000 (error per unit of distance).']::text[], learning_objectives=ARRAY['Define precision and accuracy and explain why they are independent properties of a measurement set.','Use the target/dartboard analogy to classify measurement sets as precise, accurate, both, or neither.','Relate precision to random error (scatter) and accuracy to systematic error (bias).','Interpret relative precision expressed as a ratio (e.g., 1:5,000) and the concept of closure.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='b1466895-7138-43f6-8f99-8565d7b42962';
DELETE FROM lesson_blocks WHERE lesson_id='b1466895-7138-43f6-8f99-8565d7b42962';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=25, key_takeaways=ARRAY['Significant figures are the digits that carry meaning about a measurement''s precision; the last digit is the estimated/uncertain one.','In addition/subtraction the result is limited by decimal places; in multiplication/division it is limited by the count of significant figures.','Round only the final answer, and prefer round-half-to-even to prevent systematic rounding bias.','Reporting more digits than the measurement supports is a false claim of precision.']::text[], learning_objectives=ARRAY['Count the significant figures in a measured value, applying the rules for leading, trailing, and embedded zeros.','Apply the significant-figure rules for addition/subtraction and for multiplication/division.','Round numbers correctly using the round-half-to-even (banker''s) convention to avoid cumulative rounding bias.','Recognize that significant figures communicate the precision of a measurement and must not be overstated.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7';
DELETE FROM lesson_blocks WHERE lesson_id='eafbffa3-948b-4bf6-a2d8-8d7effc3bcf7';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Random errors add in quadrature (root-sum-square), not arithmetically: E_sum = sqrt(e1^2 + e2^2 + ...).','For n equal legs each with error e, the error of the total is e*sqrt(n).','The standard error of the mean is sigma/sqrt(n): averaging n observations reduces random error by the factor sqrt(n).','For a product, relative errors combine in quadrature, so a computed area''s relative error follows the root-sum-square of its factors'' relative errors.']::text[], learning_objectives=ARRAY['Explain how random errors in measured quantities combine when those quantities are summed, differenced, or multiplied.','Apply the error-of-a-sum (and error-of-a-series) formula to compute the expected error in a total distance.','Compute the standard error of the mean and explain why averaging n observations improves precision by sqrt(n).','Apply the product rule for propagating error into a computed area or similar product.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='190ebc35-c5e8-4479-8f39-77c6e490d034';
DELETE FROM lesson_blocks WHERE lesson_id='190ebc35-c5e8-4479-8f39-77c6e490d034';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['The principle of least squares chooses the values that minimize the sum of the squared residuals, which for one quantity is the arithmetic mean.','The sample standard deviation uses n-1 (degrees of freedom) in the denominator to remain unbiased.','Least squares simultaneously adjusts many observations and produces a single best, statistically rigorous solution.','Weighted least squares assigns each observation a weight equal to the inverse of its variance, so better observations influence the result more.']::text[], learning_objectives=ARRAY['State the principle of least squares and explain why minimizing the sum of squared residuals yields the most probable values.','Compute the most probable value (mean), residuals, standard deviation, and standard error for a small set of observations.','Explain the role of redundancy (degrees of freedom) and why dividing by n-1 gives an unbiased standard deviation.','Describe weighted observations and how weights (inverse of variance) reflect differing observation reliability.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='703631b0-5d21-4272-b25a-9577c8a3bc05';
DELETE FROM lesson_blocks WHERE lesson_id='703631b0-5d21-4272-b25a-9577c8a3bc05';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Eliminate systematic error at the source: calibrate equipment, apply corrections, and design self-cancelling procedures.','Reduce random error by repeating observations and averaging, since random errors tend to cancel.','Catch blunders with redundancy and independent geometric checks (loop closures, angle sums, double measurements).','Balanced backsight/foresight distances and double-centering (face left/face right) cancel important instrument errors.']::text[], learning_objectives=ARRAY['List field procedures that eliminate or reduce systematic errors in distance, angle, and elevation measurement.','Explain how redundancy and independent checks expose blunders before they reach the office.','Describe procedures (repetition, reciprocal/balanced observations, calibration) that reduce random error and cancel instrument errors.','Connect good field practice to the error theory developed earlier in the module.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='4ae68562-9fd5-4869-8dca-f3c50cc77f9d';
DELETE FROM lesson_blocks WHERE lesson_id='4ae68562-9fd5-4869-8dca-f3c50cc77f9d';
  'eeee0350-0000-0000-0000-000000000001', 'Standard error of the mean', 'Standard error of the mean', 'Surveying Measurements — Error Theory', 'Standard error of the mean', 'numeric_input', 'easy', 'A single observation of an angle has a standard deviation of {{sigma:f1}} seconds. The angle is observed {{n}} times and the results are averaged. Compute the STANDARD ERROR OF THE MEAN, in seconds.', 'sigma/sqrt(n)', '{"decimals":2,"unit":"seconds","tolerance":0.05}', '[{"name":"sigma","type":"float","min":2,"max":12,"decimals":1},{"name":"n","type":"choice","choices":[4,9,16,25]}]'::jsonb, '[{"name":"rootn","formula":"sqrt(n)"}]'::jsonb, '[{"step_number":1,"title":"Square root of n","formula":"sqrt(n)","calculation_template":"sqrt({{n}}) = {{rootn:f1}}"},{"step_number":2,"title":"Standard error of the mean","formula":"sigma / sqrt(n)","result_template":"{{sigma:f1}} / {{rootn:f1}} = {{_answer}} seconds"}]'::jsonb, '{"method":"none"}'::jsonb, 'The standard error of the mean is sigma/sqrt(n) = {{sigma:f1}} / sqrt({{n}}) = {{sigma:f1}} / {{rootn:f1}} = {{_answer}} seconds. Averaging {{n}} observations reduces the random error by the factor sqrt({{n}}).', 'c1000003-0000-0000-0000-000000000003', ARRAY['buildout','module-3','practice']::text[], true, 'buildout:m3');
  'eeee0350-0000-0000-0000-000000000002', 'Error of a series (n equal legs)', 'Error of a series (n equal legs)', 'Surveying Measurements — Error Propagation', 'Error of a series', 'numeric_input', 'medium', 'A line is measured in {{n}} equal tape lengths. Each tape length has an independent random error of {{e:f3}} ft. Compute the expected RANDOM ERROR of the total line length, in feet.', 'e*sqrt(n)', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"n","type":"choice","choices":[4,9,16,25,36]},{"name":"e","type":"float","min":0.005,"max":0.03,"decimals":3}]'::jsonb, '[{"name":"rootn","formula":"sqrt(n)"}]'::jsonb, '[{"step_number":1,"title":"Square root of n","formula":"sqrt(n)","calculation_template":"sqrt({{n}}) = {{rootn:f1}}"},{"step_number":2,"title":"Error of the series","formula":"E = e * sqrt(n)","result_template":"{{e:f3}} x {{rootn:f1}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'For n equal legs each with random error e, the error of the series is E = e*sqrt(n) = {{e:f3}} x sqrt({{n}}) = {{e:f3}} x {{rootn:f1}} = {{_answer}} ft. The total error grows only as the square root of the number of legs.', 'c1000003-0000-0000-0000-000000000003', ARRAY['buildout','module-3','practice']::text[], true, 'buildout:m3');
  'eeee0350-0000-0000-0000-000000000003', 'Relative precision of a traverse', 'Relative precision of a traverse', 'Surveying Measurements — Precision', 'Relative precision', 'numeric_input', 'medium', 'A closed traverse has a perimeter of {{perim:f2}} ft and a linear misclosure of {{misc:f3}} ft. Express its relative precision as the denominator D in the ratio 1:D (i.e., compute perimeter / misclosure). Report D rounded to the nearest whole number.', 'round(perim/misc, 0)', '{"decimals":0,"unit":"(1 : D)","tolerance":5}', '[{"name":"perim","type":"float","min":2000,"max":6000,"decimals":2},{"name":"misc","type":"float","min":0.1,"max":0.8,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Relative precision ratio","formula":"perimeter / misclosure","calculation_template":"{{perim:f2}} / {{misc:f3}}"},{"step_number":2,"title":"Denominator D","result_template":"1 : {{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'Relative precision = perimeter / misclosure = {{perim:f2}} / {{misc:f3}} = {{_answer}}, written 1:{{_answer}}. A larger D means a more precise (tighter-closing) traverse.', 'c1000003-0000-0000-0000-000000000003', ARRAY['buildout','module-3','practice']::text[], true, 'buildout:m3');
  'eeee0350-0000-0000-0000-000000000004', 'Rounding to significant figures (product)', 'Rounding to significant figures (product)', 'Surveying Measurements — Significant Figures', 'Significant figures and rounding', 'numeric_input', 'easy', 'A rectangular parcel is measured as {{L:f1}} ft by {{W:f1}} ft (each value given to one decimal place, i.e., 4 significant figures). Compute the area and round it to 4 significant figures. Report the area in square feet to the nearest 1 sq ft.', 'round(L*W, 0)', '{"decimals":0,"unit":"sq ft","tolerance":1}', '[{"name":"L","type":"float","min":120,"max":320,"decimals":1},{"name":"W","type":"float","min":80,"max":220,"decimals":1}]'::jsonb, '[{"name":"raw","formula":"L*W"}]'::jsonb, '[{"step_number":1,"title":"Compute the raw product","formula":"L x W","calculation_template":"{{L:f1}} x {{W:f1}} = {{raw:f2}} sq ft"},{"step_number":2,"title":"Round to 4 significant figures","result_template":"{{raw:f2}} -> {{_answer}} sq ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Area = {{L:f1}} x {{W:f1}} = {{raw:f2}} sq ft. Both sides carry 4 significant figures, so the product is reported to 4 significant figures: {{_answer}} sq ft. Do not report more digits than the measurements support.', 'c1000003-0000-0000-0000-000000000003', ARRAY['buildout','module-3','practice']::text[], true, 'buildout:m3');
COMMIT;
